	(11, 3, 'Reymon', 'LGU_ADMIN', 'OTP verified', 'Auth', 'success', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36', 'http://127.0.0.1:8000/admin/login/verify', 'Admin/trainer OTP verified and login completed.', NULL, NULL, NULL, NULL, '2026-06-27 13:05:31', '2026-06-27 13:05:31', '2026-06-27 13:05:31'),
