	(22, 3, 'Reymon', 'LGU_ADMIN', 'Deleted scenario', 'Scenarios', 'warning', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36', 'http://127.0.0.1:8000/scenarios/1', 'Title: Night-time Barangay Fire', NULL, '{"id":1,"title":"Night-time Barangay Fire","short_description":"Fire breaks out in a residential block during the night shift.","affected_area":"Residential Zone 3","disaster_type":"Fire","difficulty":"Intermediate","intended_participants":"Barangay DRRM team, fire volunteers, community leaders","safety_notes":"Emphasize safe distance from fire perimeter; use proper PPE.","incident_time":"22:30","incident_time_text":"10:30 PM","general_situation":"Multiple households are affected by a rapidly spreading fire.","severity_level":"High","weather":"Dry and windy","location_type":"Urban barangay","casualty_count":0,"injured_victims_count":2,"trapped_persons_count":1,"infrastructure_damage":"Three houses partially damaged.","communication_status":"Intermittent mobile signal; radios available.","learning_objectives":"Coordinate fire response and evacuation at barangay level.","target_competencies":"Incident command, communication, evacuation management.","criteria":["Response time","Accountability of residents","Communication with responders"],"training_module_id":1,"is_required_for_module":1,"status":"published","created_by":1,"updated_by":1,"created_at":"2026-06-27T12:04:21.000000Z","updated_at":"2026-06-27T12:04:21.000000Z"}', NULL, NULL, '2026-06-27 16:25:05', '2026-06-27 16:25:05', '2026-06-27 16:25:05'),
