	(4, 5, NULL, 'Public Safety Campaign Management System', 'Registration: Jul 10, 2026 – Jul 13, 2026', '2026-07-10 09:25:23', NULL, 'waiting_for_approval', 25, 17, 0, '{"submitted_at":"2026-07-10T17:25:23+08:00","training_module_id":5,"training_title":"Fire Safety and Emergency Response","short_description":"This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.","recommended_communities":{"summary":{"total_communities":3,"high_priority":1,"medium_priority":2,"low_priority":0},"communities":[{"barangay_profile_id":7,"barangay_name":"Holy Spirit","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"High","priority_level":"Priority 1","priority_score":72,"recommendation_reason":"Recommended due to high fire susceptibility.","recommendation":"Recommended due to high fire susceptibility."},{"barangay_profile_id":4,"barangay_name":"Commonwealth","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"Medium","priority_level":"Priority 2","priority_score":55,"recommendation_reason":"Recommended based on moderate fire exposure.","recommendation":"Recommended based on moderate fire exposure."},{"barangay_profile_id":6,"barangay_name":"Bagong Silangan","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"Medium","priority_level":"Priority 2","priority_score":48,"recommendation_reason":"Recommended based on moderate fire exposure.","recommendation":"Recommended based on moderate fire exposure."}]},"target_audience":["volunteers","others","residents"],"registration_opens":"2026-07-10T18:27:00+08:00","registration_dea